import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.apache.commons.text.StringEscapeUtils;  // Import Apache Commons Text library for encoding

public class InputHandler extends HttpServlet {
    public void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);  // Encode user input to prevent XSS

        String output = "<p>" + sanitizedInput + "</p>";

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();
        out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
